+            Self::On => "On",
+        }
+    }
+
+    const fn next(self) -> Self {
+        match self {
+            Self::Off => Self::On,
+            Self::On => Self::Off,
+        }
+    }
+
+    const fn is_on(self) -> bool {
+        matches!(self, Self::On)
