+fn alias_conflict_error(
+    canonical_field: &str,
+    first_name: &str,
+    first_value: &str,
+    second_name: &str,
+    second_value: &str,
+) -> McpError {
+    legacy_tool_error(
+        "INVALID_ARGUMENT",
+        format!(
+            "Conflicting {canonical_field} values: {first_name}=\"{first_value}\" and {second_name}=\"{second_value}\"."
+        ),
+        true,
+        json!({
+            "field": canonical_field,
+            "first": { "name": first_name, "value": first_value },
